import uhashlib

COAP_VERSION = 1
COAP_TYPE_CON = 0
COAP_TYPE_NON = 1
COAP_TYPE_ACK = 2
COAP_TYPE_RST = 3

COAP_CODE_GET = 1
COAP_CODE_PUT = 3
COAP_CODE_CONTENT = 69
COAP_CODE_CHANGED = 68
COAP_CODE_BAD_REQUEST = 128
COAP_CODE_UNAUTHORIZED = 129
COAP_CODE_NOT_FOUND = 132
COAP_CODE_METHOD_NOT_ALLOWED = 133

COAP_OPTION_URI_PATH = 11
COAP_OPTION_CONTENT_FORMAT = 12

CONTENT_FORMAT_TEXT = 0
CONTENT_FORMAT_JSON = 50

MAX_PAYLOAD_SIZE = 512
MAX_URI_LENGTH = 64
MAX_TOKEN_LENGTH = 8

ALLOWED_RESOURCES = {
    b'/sensors/temp': {'methods': ['GET'], 'type': 'sensor'},
    b'/actuators/light': {'methods': ['GET', 'PUT'], 'type': 'actuator'}
}

API_KEY_HASH = None

class SecureCoapServer:
    def __init__(self, port=5683, api_key=None):
        self.port = port
        self.sock = None
        self.temp_value = 22.5
        self.light_state = False
        
        if api_key:
            global API_KEY_HASH
            API_KEY_HASH = uhashlib.sha256(api_key.encode()).digest()
        
    def start(self):
        self.sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.sock.bind(('0.0.0.0', self.port))
        self.sock.setblocking(False)
        print(f"CoAP server listening on port {self.port}")
        
    def validate_coap_header(self, data):
        if len(data) < 4:
            return None
        
        version = (data[0] >> 6) & 0x03
        if version != COAP_VERSION:
            return None
        
        msg_type = (data[0] >> 4) & 0x03
        token_length = data[0] & 0x0F
        
        if token_length > MAX_TOKEN_LENGTH:
            return None
        
        code = data[1]
        msg_id = struct.unpack('!H', data[2:4])[0]
        
        return {
            'version': version,
            'type': msg_type,
            'token_length': token_length,
            'code': code,
            'msg_id': msg_id
        }
    
    def parse_options(self, data, offset, token_length):
        options = {}
        pos = 4 + token_length
        option_number = 0
        
        while pos < len(data):
            if data[pos] == 0xFF:
                return options, pos + 1
            
            delta = (data[pos] >> 4) & 0x0F
            length = data[pos] & 0x0F
            pos += 1
            
            if delta == 13:
                if pos >= len(data):
                    return None, 0
                delta = data[pos] + 13
                pos += 1
            elif delta == 14:
                if pos + 1 >= len(data):
                    return None, 0
                delta = struct.unpack('!H', data[pos:pos+2])[0] + 269
                pos += 2
            elif delta == 15:
                return None, 0
            
            if length == 13:
                if pos >= len(data):
                    return None, 0
                length = data[pos] + 13
                pos += 1
            elif length == 14:
                if pos + 1 >= len(data):
                    return None, 0
                length = struct.unpack('!H', data[pos:pos+2])[0] + 269
                pos += 2
            elif length == 15:
                return None, 0
            
            if pos + length > len(data):
                return None, 0
            
            option_number += delta
            option_value = data[pos:pos+length]
            pos += length
            
            if option_number not in options:
                options[option_number] = []
            options[option_number].append(option_value)
        
        return options, pos
    
    def validate_uri_path(self, options):
        if COAP_OPTION_URI_PATH not in options:
            return None
        
        path_segments = options[COAP_OPTION_URI_PATH]
        
        for segment in path_segments:
            if len(segment) > MAX_URI_LENGTH:
                return None
            for byte in segment:
                if byte < 0x20 or byte > 0x7E:
                    return None
        
        uri_path = b'/' + b'/'.join(path_segments)
        
        if uri_path in ALLOWED_RESOURCES:
            return uri_path
        
        return None
    
    def validate_payload(self, payload):
        if len(payload) > MAX_PAYLOAD_SIZE:
            return None
        
        try:
            decoded = payload.decode('utf-8')
            for char in decoded:
                if ord(char) < 0x20 and char not in '\r\n\t':
                    return None
            return decoded
        except:
            return None
    
    def create_response(self, msg_type, code, msg_id, token, payload=b'', content_format=None):
        header = bytearray(4)
        header[0] = (COAP_VERSION << 6) | (msg_type << 4) | len(token)
        header[1] = code
        struct.pack_into('!H', header, 2, msg_id)
        
        response = header + token
        
        if content_format is not None:
            option_delta = COAP_OPTION_CONTENT_FORMAT
            option_length = 1
            response += bytes([option_delta << 4 | option_length, content_format])
        
        if payload:
            response += b'\xFF' + payload
        
        return response
    
    def handle_get_temp(self):
        try:
            adc = machine.ADC(4)
            reading = adc.read_u16()
            voltage = reading * 3.3 / 65535
            self.temp_value = 27 - (voltage - 0.706) / 0.001721
        except:
            pass
        
        payload = f"{self.temp_value:.1f}".encode()
        return COAP_CODE_CONTENT, payload, CONTENT_FORMAT_TEXT
    
    def handle_get_light(self):
        state = "on" if self.light_state else "off"
        payload = state.encode()
        return COAP_CODE_CONTENT, payload, CONTENT_FORMAT_TEXT
    
    def handle_put_light(self, payload_str):
        payload_lower = payload_str.lower().strip()
        
        if payload_lower in ['on', '1', 'true']:
            self.light_state = True
            return COAP_CODE_CHANGED, b'Light turned on', CONTENT_FORMAT_TEXT
        elif payload_lower in ['off', '0', 'false']:
            self.light_state = False
            return COAP_CODE_CHANGED, b'Light turned off', CONTENT_FORMAT_TEXT
        else:
            return COAP_CODE_BAD_REQUEST, b'Invalid value', CONTENT_FORMAT_TEXT
    
    def handle_request(self, data, addr):
        header = self.validate_coap_header(data)
        if not header:
            return None
        
        token_length = header['token_length']
        if len(data) < 4 + token_length:
            return None
        
        token = data[4:4+token_length]
        
        options, payload_offset = self.parse_options(data, 4, token_length)
        if options is None:
            response = self.create_response(COAP_TYPE_ACK, COAP_CODE_BAD_REQUEST, 
                                          header['msg_id'], token)
            return response
        
        uri_path = self.validate_uri_path(options)
        if not uri_path:
            response = self.create_response(COAP_TYPE_ACK, COAP_CODE_NOT_FOUND, 
                                          header['msg_id'], token)
            return response
        
        payload = b''
        if payload_offset < len(data):
            payload = data[payload_offset:]
        
        method_code = header['code']
        method_name = 'GET' if method_code == COAP_CODE_GET else 'PUT' if method_code == COAP_CODE_PUT else None
        
        if method_name not in ALLOWED_RESOURCES[uri_path]['methods']:
            response = self.create_response(COAP_TYPE_ACK, COAP_CODE_METHOD_NOT_ALLOWED, 
                                          header['msg_id'], token)
            return response
        
        if method_code == COAP_CODE_GET:
            if uri_path == b'/sensors/temp':
                code, resp_payload, content_format = self.handle_get_temp()
            elif uri_path == b'/actuators/light':
                code, resp_payload, content_format = self.handle_get_light()
            else:
                code = COAP_CODE_NOT_FOUND
                resp_payload = b''
                content_format = None
        
        elif method_code == COAP_CODE_PUT:
            if uri_path == b'/actuators/light':
                payload_str = self.validate_payload(payload)
                if payload_str is None:
                    code = COAP_CODE_BAD_REQUEST
                    resp_payload = b'Invalid payload'
                    content_format = CONTENT_FORMAT_TEXT
                else:
                    code, resp_payload, content_format = self.handle_put_light(payload_str)
